<script setup lang="ts">import type { BpmBusinessObjectDraft } from '#/api/system/bpm';import { computed } from 'vue';import { ElCheckbox,ElFormItem,ElInput,ElInputNumber } from 'element-plus';import BpmSchemaFieldTable from './bpm-schema-field-table.vue';const props=defineProps<{allKeys:string[]}>();const model=defineModel<BpmBusinessObjectDraft['lineItemSchema']>();const enabled=computed({get:()=>Boolean(model.value),set:value=>model.value=value?{name:'明细',minRows:0,maxRows:20,fields:[]}:undefined});</script>
<template><ElCheckbox v-model="enabled">包含明细行</ElCheckbox><div v-if="model" class="line-grid"><ElFormItem label="明细名称"><ElInput v-model="model.name"/></ElFormItem><ElFormItem label="最少行数"><ElInputNumber v-model="model.minRows" :min="0" :max="200"/></ElFormItem><ElFormItem label="最多行数"><ElInputNumber v-model="model.maxRows" :min="model.minRows" :max="200"/></ElFormItem></div><BpmSchemaFieldTable v-if="model" v-model="model.fields" :all-keys="allKeys" title="明细字段" zone="LINE_ITEM"/></template><style scoped>.line-grid{display:grid;grid-template-columns:2fr 1fr 1fr;gap:0 16px;margin-top:12px}@media(max-width:760px){.line-grid{grid-template-columns:1fr}}</style>
